import{_ as t,o as d,c as l,ak as o,al as a,am as i,an as r,ao as c,ap as s,aq as n,ar as h,as as g,at as p,au as b,av as m,aw as x,ax as k}from"./chunks/framework.BKYNGr60.js";const z=JSON.parse('{"title":"指令帮助","description":"","frontmatter":{},"headers":[],"relativePath":"help.md","filePath":"doc/help.md"}'),f={name:"help.md"};function u(y,e,_,v,P,j){return d(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="指令帮助" tabindex="-1">指令帮助 <a class="header-anchor" href="#指令帮助" aria-label="Permalink to “指令帮助”">​</a></h1><p>欢迎使用 mzkbot！以下是详细的功能指令指南。</p><h2 id="💬-基础对话" tabindex="-1">💬 基础对话 <a class="header-anchor" href="#💬-基础对话" aria-label="Permalink to “💬 基础对话”">​</a></h2><ul><li><strong>指令</strong>：<code>@mzkbot</code> 后接内容即可进行对话 <ul><li>示例：<code>@mzkbot 你好</code></li></ul></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">注意</p><p>在使用高峰期，对话功能可能会出现较为严重的延迟，请耐心等待</p></div><div align="center"><img src="'+a+'" alt="对话功能演示" width="60%" style="border-radius:8px;box-shadow:0 2px 5px rgba(0,0,0,0.1);"></div><h2 id="📅-每日签到" tabindex="-1">📅 每日签到 <a class="header-anchor" href="#📅-每日签到" aria-label="Permalink to “📅 每日签到”">​</a></h2><ul><li><strong>指令</strong>：<code>@mzkbot 签到</code><blockquote><p>后续会完善更多功能</p></blockquote></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">注意</p><p>高峰期可能出现延迟，请耐心等待。</p></div><div align="center"><img src="'+i+'" alt="签到功能演示" width="60%" style="border-radius:8px;box-shadow:0 2px 5px rgba(0,0,0,0.1);"></div><h2 id="🎵-娱乐互动" tabindex="-1">🎵 娱乐互动 <a class="header-anchor" href="#🎵-娱乐互动" aria-label="Permalink to “🎵 娱乐互动”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">注意</p><p>由于部分群聊使用频率过大导致bot经常被风控，现已限制其他群聊的娱乐功能使用，请移步至mzkbot的娱乐功能专群1098198311游玩</p></div><h3 id="🎶-pjsk猜歌" tabindex="-1">🎶 PJSK猜歌 <a class="header-anchor" href="#🎶-pjsk猜歌" aria-label="Permalink to “🎶 PJSK猜歌”">​</a></h3><ul><li><strong>普通猜歌</strong>：<code>@mzkbot pjsk猜歌</code></li><li><strong>2倍速猜歌</strong>：<code>@mzkbot pjsk猜歌1</code></li><li>以此类推...</li><li><strong>排行榜</strong>：<code>@mzkbot 本地猜歌排行榜</code></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">注意</p><p>此功能和SakuraBOT中的 <a href="https://yonglanws.github.io/mzkbot_web/help.html#%F0%9F%8E%AE-%E5%B0%8F%E6%B8%B8%E6%88%8F" target="_blank" rel="noreferrer">PJSK听歌识曲</a> 并不互通，我更推荐玩这个</p></div><div align="center"><img src="'+r+'" alt="猜歌演示" width="45%" style="margin:5px;border-radius:8px;"><img src="'+c+'" alt="猜歌帮助" width="60%" style="margin:5px;border-radius:8px;"></div><h3 id="🎟️-pjsk猜卡面" tabindex="-1">🎟️ PJSK猜卡面 <a class="header-anchor" href="#🎟️-pjsk猜卡面" aria-label="Permalink to “🎟️ PJSK猜卡面”">​</a></h3><ul><li><strong>猜卡面</strong>：<code>@mzkbot 猜卡面</code></li><li><strong>分数</strong>：<code>@mzkbot 猜卡面分数</code></li><li><strong>排行榜</strong>：<code>@mzkbot 猜卡面排行榜</code></li><li><strong>排行榜自定义名称</strong>：<code>@mzkbot 猜卡面自定义名称 自定义名称</code></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">注意</p><p>此功能和SakuraBOT中的 <a href="https://yonglanws.github.io/mzkbot_web/help.html#%F0%9F%8E%AE-%E5%B0%8F%E6%B8%B8%E6%88%8F" target="_blank" rel="noreferrer">PJSK猜卡面</a> 并不互通，我更推荐玩这个</p></div><div align="center"><img src="'+s+'" alt="猜卡面演示" width="45%" style="margin:5px;border-radius:8px;"><img src="'+n+'" alt="猜卡面帮助" width="60%" style="margin:5px;border-radius:8px;"></div><h3 id="🖼️-pjsk猜曲绘" tabindex="-1">🖼️ PJSK猜曲绘 <a class="header-anchor" href="#🖼️-pjsk猜曲绘" aria-label="Permalink to “🖼️ PJSK猜曲绘”">​</a></h3><ul><li><strong>猜曲绘</strong>：<code>@mzkbot 猜曲绘</code></li><li><strong>分数</strong>：<code>@mzkbot 猜曲绘分数</code></li><li><strong>排行榜</strong>：<code>@mzkbot 猜曲绘排行榜</code></li><li><strong>排行榜自定义名称</strong>：<code>@mzkbot 猜曲绘自定义名称 自定义名称</code></li></ul><div align="center"><img src="'+h+'" alt="猜曲绘演示" width="45%" style="margin:5px;border-radius:8px;"></div><h3 id="🎵-pjsk歌词猜曲" tabindex="-1">🎵 PJSK歌词猜曲 <a class="header-anchor" href="#🎵-pjsk歌词猜曲" aria-label="Permalink to “🎵 PJSK歌词猜曲”">​</a></h3><ul><li><strong>歌词猜曲</strong>：<code>@mzkbot 歌词猜曲</code></li><li><strong>分数</strong>：<code>@mzkbot 歌词猜曲分数</code></li><li><strong>排行榜</strong>：<code>@mzkbot 歌词猜曲排行榜</code></li><li><strong>排行榜自定义名称</strong>：<code>@mzkbot 歌词猜曲自定义名称 自定义名称</code></li></ul><div align="center"><img src="'+g+'" alt="歌词猜曲演示" width="45%" style="margin:5px;border-radius:8px;"></div><h3 id="🎧-网易云点歌" tabindex="-1">🎧 网易云点歌 <a class="header-anchor" href="#🎧-网易云点歌" aria-label="Permalink to “🎧 网易云点歌”">​</a></h3><ul><li><strong>标准点歌</strong>：<code>@mzkbot 点歌 歌名</code></li><li><strong>自然语言点歌</strong>：<code>@mzkbot 直接描述你想听的歌</code> 如“我想听胃弱的...”，“r-906的歌超好听！mzk能给我推荐几首吗”</li></ul><div align="center"><img src="'+p+'" alt="点歌演示1" width="45%" style="margin:5px;border-radius:8px;"><img src="'+b+'" alt="点歌演示2" width="55%" style="margin:5px;border-radius:8px;"></div><h2 id="👌-其他功能" tabindex="-1">👌 其他功能 <a class="header-anchor" href="#👌-其他功能" aria-label="Permalink to “👌 其他功能”">​</a></h2><h3 id="🎞️-流媒体解析" tabindex="-1">🎞️ 流媒体解析 <a class="header-anchor" href="#🎞️-流媒体解析" aria-label="Permalink to “🎞️ 流媒体解析”">​</a></h3><ul><li>目前支持B站，小红书，小黑盒，抖音，快手，微博，推特(可能会被墙)</li></ul><div align="center"><img src="'+m+'" alt="表情包功能" width="60%" style="border-radius:8px;box-shadow:0 2px 5px rgba(0,0,0,0.1);"></div><h3 id="👾-入群-退群提示" tabindex="-1">👾 入群/退群提示 <a class="header-anchor" href="#👾-入群-退群提示" aria-label="Permalink to “👾 入群/退群提示”">​</a></h3><div align="center"><img src="'+x+'" alt="表情包功能" width="60%" style="border-radius:8px;box-shadow:0 2px 5px rgba(0,0,0,0.1);"></div><h3 id="🖥️-服务器状态监控" tabindex="-1">🖥️ 服务器状态监控 <a class="header-anchor" href="#🖥️-服务器状态监控" aria-label="Permalink to “🖥️ 服务器状态监控”">​</a></h3><blockquote><p>我也不知道有什么用(？)</p></blockquote><div align="center"><img src="'+k+'" alt="表情包功能" width="60%" style="border-radius:8px;box-shadow:0 2px 5px rgba(0,0,0,0.1);"></div><h2 id="🌸-sakurabot-专项功能-project-sekai" tabindex="-1">🌸 SakuraBOT 专项功能 (Project Sekai) <a class="header-anchor" href="#🌸-sakurabot-专项功能-project-sekai" aria-label="Permalink to “🌸 SakuraBOT 专项功能 (Project Sekai)”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">注意</p><p>运行以下 SakuraBOT 指令时，<strong>不需要</strong>添加 <code>@mzkbot</code> 前缀，直接发送指令即可。</p><p>🌏 <strong>多服支持</strong>：涉及用户数据的指令，可添加 <code>tw</code> 或 <code>cn</code> 前缀来触发台服/国服专属功能（默认为日服）。</p></div><h3 id="📊-用户数据管理" tabindex="-1">📊 用户数据管理 <a class="header-anchor" href="#📊-用户数据管理" aria-label="Permalink to “📊 用户数据管理”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th><th style="text-align:left;">备注</th></tr></thead><tbody><tr><td style="text-align:left;"><code>绑定 ID</code></td><td style="text-align:left;">绑定游戏账号 ID</td><td style="text-align:left;">ID 可在游戏个人信息页查看</td></tr><tr><td style="text-align:left;"><code>给看</code> / <code>不给看</code></td><td style="text-align:left;">开放/关闭他人 <code>@</code> 查询你的权限</td><td style="text-align:left;">默认为「不给看」模式</td></tr><tr><td style="text-align:left;"><code>pjskprofile</code></td><td style="text-align:left;">获取个人基本信息卡片</td><td style="text-align:left;">类似旧版 Profile</td></tr><tr><td style="text-align:left;"><code>视奸</code></td><td style="text-align:left;">查看当前队伍综合力及构成</td><td style="text-align:left;">需对方开启「给看」</td></tr><tr><td style="text-align:left;"><code>逮捕</code></td><td style="text-align:left;">查询 Expert/Master FC/AP 进度</td><td style="text-align:left;"><strong>需先上传数据</strong></td></tr></tbody></table><h4 id="⚠️-数据上传重要说明" tabindex="-1">⚠️ 数据上传重要说明 <a class="header-anchor" href="#⚠️-数据上传重要说明" aria-label="Permalink to “⚠️ 数据上传重要说明”">​</a></h4><p>以下高阶功能（如 <code>rk</code>, <code>b39</code>, <code>进度</code> 等）<strong>必须上传游戏数据</strong>才能使用。</p><ol><li>请访问数据上传页面：<a href="http://go.mikuware.top/" target="_blank" rel="noreferrer">👉 点我进入上传页面</a></li><li><strong>日服玩家特权</strong>：可直接复制游戏内的“引继信息”发送给 Bot 自动完成上传（需注意引继码一次性失效，请谨慎操作或重新引继）。</li></ol><h3 id="📈-高阶数据分析-需上传数据" tabindex="-1">📈 高阶数据分析 (需上传数据) <a class="header-anchor" href="#📈-高阶数据分析-需上传数据" aria-label="Permalink to “📈 高阶数据分析 (需上传数据)”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">功能说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>rk</code></td><td style="text-align:left;">获取玩家当前排位信息</td></tr><tr><td style="text-align:left;"><code>b39</code></td><td style="text-align:left;">获取 Rating 最高的 39 首歌曲及总分 (参考用)</td></tr><tr><td style="text-align:left;"><code>pjsk b30</code></td><td style="text-align:left;">获取 Rating 最高的 30 首歌曲及平均分 (算法不同)</td></tr><tr><td style="text-align:left;"><code>pjsk进度ex</code></td><td style="text-align:left;">查询 <strong>Expert</strong> 难度歌曲完成情况 (AP/FC/Clear)</td></tr><tr><td style="text-align:left;"><code>pjsk进度apd</code></td><td style="text-align:left;">查询 <strong>Append</strong> 难度歌曲完成情况</td></tr><tr><td style="text-align:left;"><code>pjskdetail</code></td><td style="text-align:left;">获取详细信息 (金币/水晶/家具/每日挑战等) <em>介意隐私者可私聊查询</em></td></tr><tr><td style="text-align:left;"><code>pjskcard</code></td><td style="text-align:left;">获取个人卡牌图鉴 <em>支持</em> <em><code>pjskcard+角色名</code></em> <em>查单角色</em></td></tr><tr><td style="text-align:left;"><code>pjskevent</code></td><td style="text-align:left;">获取个人历史最高活动排名记录 (近10次)</td></tr></tbody></table><h3 id="🃏-智能卡组推荐-需上传数据" tabindex="-1">🃏 智能卡组推荐 (需上传数据) <a class="header-anchor" href="#🃏-智能卡组推荐-需上传数据" aria-label="Permalink to “🃏 智能卡组推荐 (需上传数据)”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">用法示例</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>组卡</code></td><td style="text-align:left;"><code>组卡 ln 橙</code></td><td style="text-align:left;">指定箱活最佳卡组 Top7 参数：<code>[队名] [属性]</code></td></tr><tr><td style="text-align:left;"><code>活动组卡</code></td><td style="text-align:left;"><code>活动组卡 龙 hard</code></td><td style="text-align:left;">当前活动最佳卡组 Top7 默认歌曲：独りんぼエンヴィー</td></tr><tr><td style="text-align:left;"><code>挑战组卡</code></td><td style="text-align:left;"><code>挑战组卡 ick 10th master</code></td><td style="text-align:left;">每日挑战最佳卡组 Top7 参数：<code>[角色] [歌曲] [难度]</code></td></tr><tr><td style="text-align:left;"><code>最强组卡</code></td><td style="text-align:left;"><code>最强组卡</code></td><td style="text-align:left;">同色同队理论最高分卡组 Top7 默认歌曲：Expert 独りんぼエンヴィー</td></tr></tbody></table><blockquote><p><strong>队名缩写参考</strong>：<code>ln</code> (Leo/need), <code>mmj</code> (MORE MORE JUMP!), <code>vbs</code> (Vivid BAD SQUAD), <code>ws</code> (Wonderlands×Showtime), <code>25</code> (25时), <code>vs</code> (Virtual Singer) <strong>属性参考</strong>：<code>绿</code>, <code>粉</code>, <code>橙</code>, <code>蓝</code>, <code>紫</code></p></blockquote><h3 id="🔍-查询与工具箱-无需上传数据" tabindex="-1">🔍 查询与工具箱 (无需上传数据) <a class="header-anchor" href="#🔍-查询与工具箱-无需上传数据" aria-label="Permalink to “🔍 查询与工具箱 (无需上传数据)”">​</a></h3><h4 id="🏆-活动与排名" tabindex="-1">🏆 活动与排名 <a class="header-anchor" href="#🏆-活动与排名" aria-label="Permalink to “🏆 活动与排名”">​</a></h4><ul><li><code>sk</code> / <code>分数线</code> / <code>sk线</code>：查询活动排名或指定档线分数 (WL活动支持加角色名查单榜)。</li><li><code>ss</code>：计算当前档线时速 (20分钟速度 × 3)。</li><li><code>wlss</code>：计算角色单榜档线时速 (日服限定)。</li><li><code>查房</code>：查看本人或目标档线最近1小时活动情况。</li><li><code>活动</code>：查看当前活动信息 (加编号查历史，如 <code>活动86</code>)。</li><li><code>findevent</code>：高级活动查询 (<code>findevent help</code> 查看用法)。</li><li><code>5v5 胜率</code> / <code>5v5 分数</code>：5v5 活动双方胜率及结算分数。</li><li><code>tf启动</code>：5v5 活动中赠送无偿火 (功能维护中)。</li></ul><h4 id="🎵-歌曲与谱面" tabindex="-1">🎵 歌曲与谱面 <a class="header-anchor" href="#🎵-歌曲与谱面" aria-label="Permalink to “🎵 歌曲与谱面”">​</a></h4><ul><li><code>pinfo</code>：查询歌曲信息 (支持花名)。 <ul><li><em>设置花名</em>：<code>pset 新昵称 to 旧昵称</code></li><li><em>删除花名</em>：<code>pdel 昵称</code></li></ul></li><li><code>难度排行</code>：<code>难度排行 10 紫</code> (支持 <code>fc</code>/<code>ap</code> 前缀)。</li><li><code>谱面预览</code>：<code>[歌曲名] 谱面预览</code> (默认 Master，支持 <code>ex</code>/<code>apd</code> 后缀)。</li><li><code>技能预览</code>：<code>[歌曲名] 技能预览</code> (支持 <code>ex</code>/<code>apd</code> 后缀)。</li><li><code>查bpm</code>：查询指定 BPM 范围的歌曲。</li><li><code>查物量</code>：查询指定物量的歌曲及难度。</li><li><code>随个</code>：<code>随个 [组合] [level]</code> (随机指定 Level 歌曲)。</li><li><code>葱什么</code>：随机返回一首歌曲信息。</li></ul><h4 id="🃏-卡牌查询" tabindex="-1">🃏 卡牌查询 <a class="header-anchor" href="#🃏-卡牌查询" aria-label="Permalink to “🃏 卡牌查询”">​</a></h4><ul><li><code>findcard</code> / <code>查卡</code>：多条件筛选卡牌 (最多3个参数：队名/角色/稀有度/属性)。</li><li><code>card</code>：<code>card [编号]</code> (查看卡面图)。</li><li><code>cardinfo</code>：<code>cardinfo [编号]</code> (查看卡牌基础信息)。</li><li><code>看</code>：<code>看 [角色名]</code> (随机返回该角色卡图)。</li></ul><h4 id="🎮-小游戏" tabindex="-1">🎮 小游戏 <a class="header-anchor" href="#🎮-小游戏" aria-label="Permalink to “🎮 小游戏”">​</a></h4><ul><li><code>pjsk听歌识曲</code>：随机播放片段，40秒内回答。 (<code>结束猜曲</code> 中断)</li><li><code>pjsk猜卡面</code>：随机截取卡面局部，40秒内回答。 (<code>结束猜卡面</code> 中断)</li><li><code>pjsk抽卡</code>： <ul><li><code>pjsk抽卡</code> (默认10连图片)</li><li><code>pjskXX连</code> (文字结果)</li><li><code>pjsk反抽卡</code> (反转概率，需指定卡池)</li></ul></li><li><code>pjsk表情制作</code>：<code>pjsk -h</code> 查看详细说明。</li></ul><h4 id="i️-其他" tabindex="-1">ℹ️ 其他 <a class="header-anchor" href="#i️-其他" aria-label="Permalink to “ℹ️ 其他”">​</a></h4><ul><li><code>id</code>：查看当前 QQ 绑定的游戏 ID。</li><li><code>charinfo</code>：查询角色所有花名 (<code>charset</code>/<code>chardel</code> 可修改)。</li></ul><blockquote><p>📢 <strong>自动推送</strong>：每日 <strong>10:00</strong> 自动检测更新并推送至订阅群，活动期间推送结活 Live 通知。</p></blockquote>',62)])])}const S=t(f,[["render",u]]);export{z as __pageData,S as default};
